        _context.SaveChanges();

        var retrieved = _context.Departments.Include(d => d.Administrator).First();
        Assert.Equal("User", retrieved.Administrator!.LastName);
    }

    [Fact]
    public void CourseAssignment_CompositeKey_Works()
    {
        var instructor = new Instructor { FirstMidName = "I", LastName = "N", HireDate = DateTime.Now };
        _context.Instructors.Add(instructor);
        var dept = new Department { Name = "D", Budget = 0, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 200, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var assignment = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        var retrieved = _context.CourseAssignments.First();
        Assert.Equal(course.CourseID, retrieved.CourseID);
        Assert.Equal(instructor.ID, retrieved.InstructorID);
    }

    [Fact]
    public void Enrollment_RelationshipsWork()
    {
        var student = new Student { FirstMidName = "S", LastName = "T", EnrollmentDate = DateTime.Now };
        _context.Students.Add(student);
        var dept = new Department { Name = "D", Budget = 0, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 300, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A };
        _context.Enrollments.Add(enrollment);
        _context.SaveChanges();

        var retrieved = _context.Enrollments.Include(e => e.Student).Include(e => e.Course).First();
        Assert.Equal("T", retrieved.Student.LastName);
        Assert.Equal("C", retrieved.Course.Title);
        Assert.Equal(Grade.A, retrieved.Grade);
    }

    [Fact]
    public void OfficeAssignment_OneToOneRelationship()
    {
        var instructor = new Instructor { FirstMidName = "O", LastName = "A", HireDate = DateTime.Now };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var office = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
        _context.OfficeAssignments.Add(office);
        _context.SaveChanges();

        var retrieved = _context.Instructors.Include(i => i.OfficeAssignment).First();
        Assert.Equal("Room 101", retrieved.OfficeAssignment!.Location);
    }

    [Fact]
    public void Person_FullName_ReturnsLastCommaFirst()
    {
        var student = new Student { FirstMidName = "John", LastName = "Doe", EnrollmentDate = DateTime.Now };
        Assert.Equal("Doe, John", student.FullName);
    }

    [Fact]
    public void Notification_CanBeStored()
    {
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test",
            CreatedAt = DateTime.Now,
            CreatedBy = "Test",
            IsRead = false
        };
        _context.Notifications.Add(notification);
        _context.SaveChanges();

        var retrieved = _context.Notifications.First();
        Assert.Equal("Student", retrieved.EntityType);
    }
}

