namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests : IDisposable
{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        var retrieved = _context.Students.First();
        Assert.Equal("Test", retrieved.FirstMidName);
        Assert.Equal("Student", retrieved.LastName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        var dept = new Department { Name = "Test", Budget = 100, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 100, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var retrieved = _context.Courses.Include(c => c.Department).First();
        Assert.Equal("Test Course", retrieved.Title);
        Assert.Equal("Test", retrieved.Department.Name);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        var instructor = new Instructor
        {
            FirstMidName = "John",
            LastName = "Doe",
            HireDate = DateTime.Parse("2020-01-01")
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var retrieved = _context.Instructors.First();
        Assert.Equal("Doe", retrieved.LastName);
    }

    [Fact]
    public void CanAddDepartmentWithAdministrator()
    {
        var instructor = new Instructor { FirstMidName = "Admin", LastName = "User", HireDate = DateTime.Now };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var dept = new Department { Name = "CS", Budget = 500000, StartDate = DateTime.Now, InstructorID = instructor.ID };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var retrieved = _context.Departments.Include(d => d.Administrator).First();
        Assert.Equal("User", retrieved.Administrator!.LastName);
    }

    [Fact]
    public void CourseAssignment_CompositeKey_Works()
    {
        var instructor = new Instructor { FirstMidName = "I", LastName = "N", HireDate = DateTime.Now };
        _context.Instructors.Add(instructor);
        var dept = new Department { Name = "D", Budget = 0, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course { CourseID = 200, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var assignment = new CourseAssignment { CourseID = course.CourseID, InstructorID = instructor.ID };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        var retrieved = _context.CourseAssignments.First();
        Assert.Equal(course.CourseID, retrieved.CourseID);
        Assert.Equal(instructor.ID, retrieved.InstructorID);
    }

    [Fact]
    public void Enrollment_RelationshipsWork()
    {
