using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System.Text;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsAllCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
        Assert.Equal(3, model.Count());
    }

    [Fact]
    public void Details_ValidId_ReturnsCourse()
    {
        var result = _controller.Details(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Create_GET_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_POST_ValidCourse_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(4, _context.Courses.Count());
    }

    [Fact]
    public void Create_POST_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 9999, DepartmentID = 1 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_POST_InvalidFileExtension_ReturnsView()
    {
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
        var file = CreateMockFormFile("test.exe", 1024);

        var result = _controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_POST_FileTooLarge_ReturnsView()
    {
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
        var file = CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

        var result = _controller.Create(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_POST_ValidImage_UploadsAndRedirects()
    {
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
        var file = CreateMockFormFile("test.jpg", 1024);

        var result = _controller.Create(course, file) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        var savedCourse = _context.Courses.Find(9999);
        Assert.NotNull(savedCourse);
        Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
    }

    [Fact]
    public void Edit_GET_ValidId_ReturnsCourse()
    {
        var result = _controller.Edit(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_GET_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_POST_ValidCourse_RedirectsToIndex()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
        course.Title = "Updated Chemistry";

        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_POST_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, DepartmentID = 1 };

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_POST_InvalidFileExtension_ReturnsView()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
        var file = CreateMockFormFile("test.txt", 1024);

        var result = _controller.Edit(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_POST_FileTooLarge_ReturnsView()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
        var file = CreateMockFormFile("test.png", 6 * 1024 * 1024);

        var result = _controller.Edit(course, file) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Delete_GET_ValidId_ReturnsCourse()
    {
        var result = _controller.Delete(1050) as ViewResult;

        Assert.NotNull(result);
        var course = Assert.IsType<Course>(result.Model);
        Assert.Equal("Chemistry", course.Title);
    }

    [Fact]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
    {
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(2, _context.Courses.Count());
    }

    private static IFormFile CreateMockFormFile(string fileName, long size)
    {
        var content = new byte[Math.Min(size, 1024)];
        var stream = new MemoryStream(content);
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns(fileName);
        mockFile.Setup(f => f.Length).Returns(size);
        mockFile.Setup(f => f.OpenReadStream()).Returns(stream);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
        return mockFile.Object;
    }
}

