using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class DbInitializerTests
{
    [Fact]
    public void Initialize_SeedsDataIntoEmptyDatabase()
    {
        var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.True(context.Students.Any());
        Assert.True(context.Instructors.Any());
        Assert.True(context.Departments.Any());
        Assert.True(context.Courses.Any());
        Assert.True(context.Enrollments.Any());
        Assert.True(context.CourseAssignments.Any());
        Assert.True(context.OfficeAssignments.Any());
    }

    [Fact]
    public void Initialize_DoesNotDuplicateDataOnSecondCall()
    {
        var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);
        var studentCount = context.Students.Count();

        DbInitializer.Initialize(context);
        Assert.Equal(studentCount, context.Students.Count());
    }

    [Fact]
    public void Initialize_Creates8Students()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(8, context.Students.Count());
    }

    [Fact]
    public void Initialize_Creates5Instructors()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(5, context.Instructors.Count());
    }

    [Fact]
    public void Initialize_Creates4Departments()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(4, context.Departments.Count());
    }

    [Fact]
    public void Initialize_Creates7Courses()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(7, context.Courses.Count());
    }

    [Fact]
    public void Initialize_CreatesEnrollments()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(11, context.Enrollments.Count());
    }

    [Fact]
    public void Initialize_CreatesOfficeAssignments()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(3, context.OfficeAssignments.Count());
    }

    [Fact]
    public void Initialize_CreatesCourseAssignments()
    {
        var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);

        Assert.Equal(8, context.CourseAssignments.Count());
    }
}

