using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private int GetInstructorId(string lastName) => _context.Instructors.First(i => i.LastName == lastName).ID;

    [Fact]
    public void Index_NoParams_ReturnsAllInstructors()
    {
        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Equal(3, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_ReturnsCourses()
    {
        var id = GetInstructorId("Abercrombie");
        var result = _controller.Index(id, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithCourseId_ReturnsEnrollments()
    {
        var instructorId = GetInstructorId("Abercrombie");
        var result = _controller.Index(instructorId, 1050) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Enrollments);
    }

    [Fact]
    public void Details_ValidId_ReturnsInstructor()
    {
        var id = GetInstructorId("Abercrombie");
        var result = _controller.Details(id) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Abercrombie", instructor.LastName);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_GET_ReturnsViewWithCourses()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.NotNull(instructor.CourseAssignments);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    [Fact]
    public void Create_POST_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(4, _context.Instructors.Count());
    }

    [Fact]
    public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
    {
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var selectedCourses = new[] { "1050", "4022" };

        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal(2, instructor.CourseAssignments.Count);
    }

    [Fact]
    public void Create_POST_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_GET_ValidId_ReturnsInstructor()
    {
        var id = GetInstructorId("Abercrombie");
        var result = _controller.Delete(id) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Abercrombie", instructor.LastName);
    }

    [Fact]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_GET_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructor_NullsDepartmentAdmin()
    {
        var id = GetInstructorId("Abercrombie");
        var deptId = _context.Departments.First(d => d.InstructorID == id).DepartmentID;

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(2, _context.Instructors.Count());

        var dept = _context.Departments.Find(deptId);
        Assert.Null(dept!.InstructorID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorWithOfficeAssignment()
    {
        var id = GetInstructorId("Fakhouri");

        var result = _controller.DeleteConfirmed(id) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(2, _context.Instructors.Count());
    }
}

